// Transform CoinGecko response into rows for asset_prices table
// Supports multiple currencies and additional market data
const coingeckoData = $input.first().json;
const timestamp = new Date().toISOString();
const results = [];

for (const [symbol, data] of Object.entries(coingeckoData)) {
  results.push({
    symbol: symbol.toUpperCase(),
    price: data.usd || 0,
    volume: data.usd_24h_vol || null,
    market_cap: data.usd_market_cap || null,
    change_24h: data.usd_24h_change || null,
    price_eur: data.eur || null,
    price_gbp: data.gbp || null,
    price_jpy: data.jpy || null,
    currency: 'usd',
    timestamp: data.last_updated_at 
      ? new Date(data.last_updated_at * 1000).toISOString() 
      : timestamp,
    source: 'coingecko'
  });
}

return results.map(row => ({ json: row }));

// Extract headlines from news feed response
// Supports multiple news API formats
const newsData = $input.first().json;
const results = [];

// Helper to convert timestamp to ISO string
function toISOString(timestamp) {
  if (!timestamp) return new Date().toISOString();
  // If it's a number (Unix timestamp), convert it
  if (typeof timestamp === 'number') {
    return new Date(timestamp * 1000).toISOString();
  }
  // If it's already a string, check if it's valid ISO
  if (typeof timestamp === 'string') {
    const date = new Date(timestamp);
    return isNaN(date.getTime()) ? new Date().toISOString() : date.toISOString();
  }
  return new Date().toISOString();
}

// CoinGecko News API format: { data: [...] }
if (newsData.data && Array.isArray(newsData.data)) {
  for (const item of newsData.data.slice(0, 50)) {
    results.push({
      headline: item.title || item.news || item.description,
      source: item.author || item.source || 'CoinGecko',
      timestamp: toISOString(item.updated_at || item.published_at),
      url: item.url || null
    });
  }
}
// CryptoPanic format: { results: [...] }
else if (newsData.results && Array.isArray(newsData.results)) {
  for (const item of newsData.results.slice(0, 50)) {
    results.push({
      headline: item.title,
      source: item.source?.title || item.domain || 'unknown',
      timestamp: toISOString(item.published_at),
      url: item.url || null
    });
  }
}
// Generic array format
else if (Array.isArray(newsData)) {
  for (const item of newsData.slice(0, 50)) {
    results.push({
      headline: item.title || item.headline,
      source: item.source || 'unknown',
      timestamp: toISOString(item.publishedAt || item.timestamp),
      url: item.url || null
    });
  }
}

// Fallback: If still empty, create a dummy news item to prevent workflow failure
if (results.length === 0) {
  results.push({
    headline: 'No news available - Market data ingestion continues',
    source: 'system',
    timestamp: new Date().toISOString(),
    url: null
  });
}

// Return headlines array for sentiment API
return [{ json: { headlines: results.map(r => r.headline), newsItems: results } }];

// Merge news items with their sentiment scores
const inputData = $input.first().json;
const sentimentResults = inputData.results || [];

// Get the original news items passed through
const prevNode = $('Extract Headlines').first().json;
const newsItems = prevNode.newsItems || [];

const merged = [];
for (let i = 0; i < newsItems.length; i++) {
  const news = newsItems[i];
  const sentiment = sentimentResults[i] || {};

  merged.push({
    headline: news.headline,
    source: news.source,
    timestamp: news.timestamp,
    url: news.url,
    ai_sentiment_score: sentiment.normalized_score ?? null
  });
}

return merged.map(row => ({ json: row }));

// Log execution summary
const pricesInserted = $('Insert Prices').all().length;
const newsInserted = $('Insert News').all().length;

return [{
  json: {
    status: 'success',
    timestamp: new Date().toISOString(),
    prices_inserted: pricesInserted,
    news_inserted: newsInserted
  }
}];
